sql:
SELECT AVG(check_in_count) AS average_check_ins_per_user
FROM (
    SELECT user_id, COUNT(check_in_id) AS check_in_count
    FROM check_ins
    GROUP BY user_id
) AS check_in_counts;

external_knowledge:
- 'explorers' refers to the users in this context;
- 'distant lands' metaphorically represents the distinct venues each user has visited;
- The ranking is determined by the number of unique venues visited, where a higher number indicates a more extensive exploration.

sql:
SELECT COUNT(DISTINCT user_id) AS user_count
FROM check_ins
WHERE venue_id = '0';

SELECT ad_content
FROM advertisements
WHERE ad_type = 'banner';

SELECT COUNT(check_in_id) AS number_of_check_ins
FROM check_ins
WHERE venue_id = '0';

SELECT AVG(rating) AS average_rating
FROM venue_reviews
WHERE venue_id = '0' AND review_date BETWEEN '2012-01-01' AND '2012-12-31';

external_knowledge:
- "Travelers" metaphorically represent users;
- "Touched down in our virtual port" refers to users making check-ins;
- "Unique travelers" means unique users based on user ID;
- "Cast their shadow within our walls" symbolizes multiple check-ins by the same user.

sql:
SELECT AVG(rating) AS average_rating
FROM venue_reviews
WHERE review_date BETWEEN date('now','-1 year') AND date('now');

SELECT AVG(review_count) AS average_reviews_per_venue
FROM (
  SELECT venue_id, COUNT(review_id) AS review_count
  FROM venue_reviews
  GROUP BY venue_id
) AS subquery;

SELECT city, COUNT(venue_id) AS number_of_venues
FROM venues
GROUP BY city;

SELECT COUNT(venue_id) AS total_venues
FROM venues
WHERE city = 'London';

SELECT COUNT(promotion_id) AS total_promotions
FROM venue_promotions
WHERE venue_id = '0';
